 33→const toCount = (value: unknown): number | null => {
 34→  const parsed = Number(value);
 35→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
 36→};
 37→
 38→const resolveCount = (
 39→  aggregate: Array<{count?: number}> | undefined,
 40→  fallback?: number,
 41→): number => {
 42→  return toCount(aggregate?.[0]?.count) ?? toCount(fallback) ?? 0;
 43→};
 44→
 45→const formatRelativeDate = (value: string | undefined): string => {
 46→  if (!value) return '';
 47→  const date = new Date(value);
 48→  if (Number.isNaN(date.getTime())) return value;
 49→  const now = Date.now();
 50→  const diff = now - date.getTime();
 51→  const mins = Math.floor(diff / 60000);
 52→  if (mins < 1) return 'Just now';
 53→  if (mins < 60) return `${mins}m ago`;
 54→  const hours = Math.floor(mins / 60);
 55→  if (hours < 24) return `${hours}h ago`;
 56→  const days = Math.floor(hours / 24);
 57→  if (days < 7) return `${days}d ago`;
 58→  return date.toLocaleDateString(undefined, {month: 'short', day: 'numeric', year: 'numeric'});
 59→};
 60→
 61→const extractBannerImage = (content: string | null | undefined): string | null => {
 62→  if (!content) return null;
 63→  try {
 64→    const parsed = JSON.parse(content);
 65→    const findImage = (node: any): string | null => {
 66→      if (node.type === 'image' && node.src) return node.src;
 67→      if (node.children) {
 68→        for (const child of node.children) {
 69→          const found = findImage(child);
 70→          if (found) return found;
 71→        }
 72→      }
 73→      return null;
 74→    };
 75→    return findImage(parsed.root ?? parsed);
 76→  } catch {
 77→    return null;
 78→  }
 79→};
