 98→  });
 99→
100→  const likeMutation = useMutation({
101→    mutationFn: async () => {
102→      const journal = detailQuery.data?.journal;
103→      const receiverId = journal?.user_id ?? journal?.users?.id;
104→      if (!token) throw new Error('Please log in to like this post.');
105→      if (!journal?.id || !receiverId) throw new Error('Missing journal data.');
106→      const metadata = session?.user.user_metadata as {name?: string; avatar_url?: string} | undefined;
107→      return socialApi.likeJournal(token, {
108→        journalId: journal.id,
109→        receiverId,
110→        sendername: metadata?.name,
111→        senderImageUrl: metadata?.avatar_url,
112→        senderEmail: session?.user.email,
113→      });
114→    },
115→    onSuccess: () => {
116→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
117→      queryClient.invalidateQueries({queryKey: ['feed']});
118→    },
119→    onError: e => Alert.alert('Like failed', e instanceof Error ? e.message : 'Error'),
120→  });
121→
