127→    onSuccess: () => {
128→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
129→      queryClient.invalidateQueries({queryKey: ['feed']});
130→    },
131→    onError: e => Alert.alert('Bookmark failed', e instanceof Error ? e.message : 'Error'),
132→  });
133→
